@Data
public static class CompletionParams {
    @JsonProperty("max_tokens")
    private Integer maxTokens;

    private Boolean stream = true;  // 流式输出

    private Float temperature = 0.1f;        // 低温，保证稳定性
    @JsonProperty("top_p")
    private Float topP = 0.9f;               // 核采样
    @JsonProperty("frequency_penalty")
    private Float frequencyPenalty = 0.5f;   // 中等频率惩罚
    @JsonProperty("presence_penalty")
    private Float presencePenalty = 0.5f;    // 中等存在惩罚
}
